    protected fun toggleAutoAdvance() {
        val preferences = sharedPrefs()
        val oldValue = preferences.getBoolean("timeoutAnswer", false)
        val newValue = !oldValue

        preferences.edit().putBoolean("timeoutAnswer", newValue).apply()

        // Keep the legacy behavior: auto-advance implies keep screen on
        val keepScreenOn = preferences.getBoolean("keepScreenOn", false)
        if (newValue || keepScreenOn) {
            window.addFlags(WindowManager.LayoutParams.FLAG_KEEP_SCREEN_ON)
        } else {
            window.clearFlags(WindowManager.LayoutParams.FLAG_KEEP_SCREEN_ON)
        }

        // Apply changes immediately
        if (colIsOpenUnsafe()) {
            automaticAnswer = AutomaticAnswer.createInstance(this, preferences, getColUnsafe)

            // If we've turned the feature off, stop any pending tasks immediately
            if (!newValue) {
                automaticAnswer.disable()
            } else {
                // Reschedule for the current side if we are not waiting for audio callbacks
                if (isDisplayingAnswer) {
                    automaticAnswer.onDisplayAnswer()
                } else {
                    automaticAnswer.onDisplayQuestion()
                }

                launchCatchingTask {
                    if (!automaticAnswerShouldWaitForAudio()) {
                        if (isDisplayingAnswer) {
                            automaticAnswer.scheduleAutomaticDisplayQuestion()
                        } else {
                            automaticAnswer.scheduleAutomaticDisplayAnswer()
                        }
                    }
                }
            }
        }

        invalidateOptionsMenu()
    }
